const a = [
  {"id":351,"text":"Developmentally, the cerebellum develops from which of the following?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 392.","responses":[{"text":"Diencephalon","correct":false,"visible":false},{"text":"Metencephalon","correct":true,"visible":false},{"text":"Telencephalon","correct":false,"visible":false},{"text":"Mesencephalon","correct":false,"visible":false},{"text":"Myelencephalon","correct":false,"visible":false}]},{"id":1765,"text":"The second pharyngeal pouch gives rise to which of the following?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 11th ed. Saunders/Elsevier; 2020: 161.","responses":[{"text":"Adenoids","correct":false,"visible":false},{"text":"Palatine tonsil","correct":true,"visible":false},{"text":"Tubal tonsils","correct":false,"visible":false},{"text":"Pharyngeal tonsil","correct":false,"visible":false},{"text":"Lingual tonsil","correct":false,"visible":false}]},{"id":1766,"text":"An 18-year-old boy has a head injury in which an immobile joint between the flat bones of the skull is disrupted. Which of the following types of joint is involved?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 830.","responses":[{"text":"Symphysis","correct":false,"visible":false},{"text":"Condyloid joint","correct":false,"visible":false},{"text":"Suture","correct":true,"visible":false},{"text":"Hinge joint","correct":false,"visible":false},{"text":"Plane joint","correct":false,"visible":false}]},{"id":1767,"text":"A 20-year-old boy is brought to the outpatient department with a complaint of swelling below and behind the angle of the mandible. On examination, the doctor notices that it is a palpable jugulodigastric lymph node. Which of the following is the site of pathology?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1039.","responses":[{"text":"Tongue","correct":false,"visible":false},{"text":"Palatine tonsil","correct":true,"visible":false},{"text":"Cheek","correct":false,"visible":false},{"text":"Upper eyelid","correct":false,"visible":false},{"text":"Lower eyelid","correct":false,"visible":false}]},{"id":1768,"text":"A 25-year-old woman is brought to the outpatient department with a complaint of infection (ulcer) on the tongue. Which group of lymph nodes will become enlarged?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1028.","responses":[{"text":"Jugulo-omohyoid","correct":true,"visible":false},{"text":"Superficial cervical","correct":false,"visible":false},{"text":"Occipital","correct":false,"visible":false},{"text":"Jugulodigastric","correct":false,"visible":false},{"text":"Supraclavicular","correct":false,"visible":false}]},{"id":1769,"text":"A 63-year-old man fails to maintain balance during linear motion. Which of the following sensory organs is responsible for detecting linear acceleration?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 706.","responses":[{"text":"Organ of corti","correct":false,"visible":false},{"text":"Cochlear duct","correct":false,"visible":false},{"text":"Cristae","correct":false,"visible":false},{"text":"Saccules","correct":false,"visible":false},{"text":"Maculae","correct":true,"visible":false}]},{"id":1770,"text":"An 8-year-old boy is brought to the outpatient department with complaints of nasal blockage and impairment of hearing. On examination, a diagnosis of adenoiditis is made due to inflammation of the tonsils. Where is the appropriate group of tonsils present?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1037.","responses":[{"text":"Nasopharynx","correct":true,"visible":false},{"text":"Oropharynx","correct":false,"visible":false},{"text":"Laryngopharynx","correct":false,"visible":false},{"text":"Tonsillar fossa","correct":false,"visible":false},{"text":"Salpingopharynx","correct":false,"visible":false}]},{"id":1771,"text":"A clinician examines the extrinsic musculature of the eyes of a 50-year-old female patient. All extraocular muscles are functioning fine except one. Which of the following muscles is affected based on the action mentioned?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 926.","responses":[{"text":"Superior oblique-looks medially and upwards","correct":true,"visible":false},{"text":"Medial rectus- looks medially","correct":false,"visible":false},{"text":"Superior rectus-looks medially and upwards","correct":false,"visible":false},{"text":"Inferior rectus-looks downwards","correct":false,"visible":false},{"text":"Lateral rectus-looks laterally","correct":false,"visible":false}]},{"id":1772,"text":"Which of the following is a feature of complete anterior cleft anomaly?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 11th ed. Saunders/Elsevier; 2020: 183.","responses":[{"text":"Cleft extends through maxilla and hard palate","correct":false,"visible":false},{"text":"Cleft extends through lips and alveolar part of maxilla","correct":false,"visible":false},{"text":"Cleft extends through lip, maxilla, soft palate, and hard palate","correct":false,"visible":false},{"text":"Cleft extends through lips and alveolar part of maxilla to the incisive fossa on both sides","correct":false,"visible":false},{"text":"Cleft extends through upper lip and alveolar part of maxilla to the incisive fossa","correct":true,"visible":false}]},{"id":1810,"text":"A patient comes to the outpatient department with a complaint of pain in the throat and impairment of hearing. Otoscopic examination reveals the blockage of the auditory tube due to the spread of infection from the pharynx. What is the appropriate site of infection in the pharynx?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 947.","responses":[{"text":"Oropharynx","correct":false,"visible":false},{"text":"Nasopharynx","correct":true,"visible":false},{"text":"Salpingopharynx","correct":false,"visible":false},{"text":"Palatopharynx","correct":false,"visible":false},{"text":"Laryngopharynx","correct":false,"visible":false}]},{"id":1811,"text":"A patient's magnetic resonance imaging (MRI) reveals that the brain tumor is pressing on the superior orbital fissure. Which of the following structures will not be affected?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 854.","responses":[{"text":"Abducent nerve","correct":false,"visible":false},{"text":"Trochlear nerve","correct":false,"visible":false},{"text":"Optic nerve","correct":true,"visible":false},{"text":"Occulomotor nerve","correct":false,"visible":false},{"text":"Nasociliary nerve","correct":false,"visible":false}]},{"id":1812,"text":"While examining the lateral view of the X-ray of the skull, a radiologist points out a region that is the meeting point of the parietomastoid, occipitomastoid, and lambdoid sutures. What point is he referring to?","explanation":"The **asterion** is an anatomical landmark located at the junction of the parietomastoid, occipitomastoid, and lambdoid sutures. It is situated in the temporal region of the skull, typically at the level of the asterion.\r\n\r\nIdentifying the asterion is important for various clinical purposes, including neurosurgery, radiology, and anatomical localization. For example, it serves as a reference point for the placement of burr holes during surgical procedures and is also used in cranial measurements and radiographic interpretation.","reference":"Chung KW, Chung HM, Halliday NL. BRS: Gross Anatomy. 8th ed. Wolters Kluwer Health; 2015: 369.","responses":[{"text":"Lambda","correct":false,"visible":false},{"text":"Inion","correct":false,"visible":false},{"text":"Bregma","correct":false,"visible":false},{"text":"Asterion","correct":true,"visible":false},{"text":"Pterion","correct":false,"visible":false}]},{"id":1813,"text":"A surgeon, while performing surgery for removal of lymph nodes from the posterior triangle of the neck, is liable to damage which one of the following nerves?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 889.","responses":[{"text":"Maxillary nerve","correct":false,"visible":false},{"text":"Supraclavicular nerve","correct":false,"visible":false},{"text":"Lesser occipital nerve","correct":false,"visible":false},{"text":"Accessory nerve","correct":true,"visible":false},{"text":"Greater auricular nerve","correct":false,"visible":false}]},{"id":1814,"text":"Which of the following is incorrect regarding the features of the pigmented epithelium layer of the retina?","explanation":null,"reference":"Siddiqui LH. Medical Histology Text And Atlas. 6th ed. Paramount; 2019: 247-248.","responses":[{"text":"It consists of simple columnar epithelium","correct":false,"visible":false},{"text":"The cells show phagocytic activity","correct":false,"visible":false},{"text":"It consists of stratified columnar epithelium","correct":true,"visible":false},{"text":"It strongly adheres to Bruch's membrane of choroid","correct":false,"visible":false},{"text":"It contains stores of vitamin A","correct":false,"visible":false}]},{"id":1815,"text":"Which of the following statement is incorrect about the retina of the eye?","explanation":null,"reference":"Siddiqui LH. Medical Histology Text And Atlas. 6th ed. Paramount; 2019: 247-248, 251.","responses":[{"text":"It is richly vascularized","correct":false,"visible":false},{"text":"It terminates anteriorly at orra serrata","correct":false,"visible":false},{"text":"It is the innermost layer of eye and is responsible for photoreception","correct":false,"visible":false},{"text":"It is easily detached from underlying choroid","correct":true,"visible":false},{"text":"A shallow depression called fovea is present in its posterior wall containing only cones","correct":false,"visible":false}]},{"id":1816,"text":"The activation of the receptor by odorant particle further activates which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 680.","responses":[{"text":"Alpha subunit","correct":false,"visible":false},{"text":"Ion channel","correct":false,"visible":false},{"text":"Beta subunit","correct":false,"visible":false},{"text":"Tyrosine complex","correct":false,"visible":false},{"text":"G-protein complex","correct":true,"visible":false}]},{"id":1817,"text":"Which of the following is not a feature of a typical cervical vertebra?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 67, 69.","responses":[{"text":"Triangular vertebral foramen","correct":false,"visible":false},{"text":"Body","correct":false,"visible":false},{"text":"Bifid spinous process","correct":false,"visible":false},{"text":"Transverse foramen","correct":false,"visible":false},{"text":"Dens","correct":true,"visible":false}]},{"id":1818,"text":"Aqueous humor is secreted by which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 635.","responses":[{"text":"Ciliary body","correct":true,"visible":false},{"text":"Iris","correct":false,"visible":false},{"text":"Scleral glands","correct":false,"visible":false},{"text":"Arteries of retina","correct":false,"visible":false},{"text":"Lacrimal glands","correct":false,"visible":false}]},{"id":1819,"text":"Auditory signals are transmitted mainly by which of the following cells?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 667.","responses":[{"text":"Outer hair cells","correct":false,"visible":false},{"text":"Reticular lamina","correct":false,"visible":false},{"text":"Inner hair cells","correct":true,"visible":false},{"text":"Rods of Corti","correct":false,"visible":false},{"text":"Inner and central cells","correct":false,"visible":false}]},{"id":1820,"text":"Bending of cilia of hair cells in the organ of Corti causes which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 668.","responses":[{"text":"Sodium conductance","correct":false,"visible":false},{"text":"Magnesium conductance","correct":false,"visible":false},{"text":"Potassium conductance","correct":true,"visible":false},{"text":"Chloride conductance","correct":false,"visible":false},{"text":"Potassium and sodium conductance","correct":false,"visible":false}]},{"id":1821,"text":"Which bone has a major contribution to the formation of the nasal septum?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1061-1063.","responses":[{"text":"Nasal spine of frontal bone","correct":false,"visible":false},{"text":"Maxillary palatine crest","correct":false,"visible":false},{"text":"Rostrum of sphenoid bone","correct":false,"visible":false},{"text":"Perpendicular plate of ethmoid bone","correct":true,"visible":false},{"text":"Perpendicular plate of palatine bone","correct":false,"visible":false}]},{"id":1927,"text":"Bone of middle ear that covers the oval window develops from which of the following?","explanation":null,"reference":"1) Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 947.\r\n\r\n2) Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 160.","responses":[{"text":"Sixth pharyngeal arch","correct":false,"visible":false},{"text":"Fourth pharyngeal arch","correct":false,"visible":false},{"text":"Hyoid arch","correct":true,"visible":false},{"text":"Mandibular arch","correct":false,"visible":false},{"text":"Third pharyngeal arch","correct":false,"visible":false}]},{"id":1928,"text":"Which of the following bones is not involved in the formation of pterion?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1115.","responses":[{"text":"Occipital bone","correct":true,"visible":false},{"text":"Temporal bone","correct":false,"visible":false},{"text":"Parietal bone","correct":false,"visible":false},{"text":"Frontal bone","correct":false,"visible":false},{"text":"Sphenoid bone","correct":false,"visible":false}]},{"id":1930,"text":"Which of the following is correct regarding parts of bones of the head and neck?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 849, 851.","responses":[{"text":"Styloid process is a part of temporal bone","correct":true,"visible":false},{"text":"Parietal bone has a petrous part","correct":false,"visible":false},{"text":"Posterior nasal spine is a part of maxilla","correct":false,"visible":false},{"text":"Pterygoid process is a part of temporal bone","correct":false,"visible":false},{"text":"Inferior nasal concha is a part of ethmoid bone","correct":false,"visible":false}]},{"id":1931,"text":"What is the most common location for a thyroglossal duct cyst?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 169.","responses":[{"text":"Superior mediastinum","correct":false,"visible":false},{"text":"Inferior to hyoid bone","correct":true,"visible":false},{"text":"Superior to hyoid bone","correct":false,"visible":false},{"text":"Anterior to hyoid bone","correct":false,"visible":false},{"text":"At the base of tongue","correct":false,"visible":false}]},{"id":1932,"text":"Considering the structure of the eyeball, which of the following is not crossed by light rays?","explanation":null,"reference":null,"responses":[{"text":"Vitreous humor","correct":false,"visible":false},{"text":"Pupil","correct":false,"visible":false},{"text":"Sclera","correct":true,"visible":false},{"text":"Lens","correct":false,"visible":false},{"text":"Cornea","correct":false,"visible":false}]},{"id":1933,"text":"A lesion of the optic chiasma causes which of the following conditions?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 562.","responses":[{"text":"Loss of vision in the left eye","correct":false,"visible":false},{"text":"Homonymous contralateral hemianopsia","correct":false,"visible":false},{"text":"Homonymous hemianopsia","correct":false,"visible":false},{"text":"Loss of vision in the right eye","correct":false,"visible":false},{"text":"Heteronymous bitemporal hemianopsia","correct":true,"visible":false}]},{"id":1934,"text":"The dorsal component of the auditory vesicle does not give rise to which of the following structures?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 428.","responses":[{"text":"Semicircular canals","correct":false,"visible":false},{"text":"Membranous labyrinth","correct":false,"visible":false},{"text":"Saccule","correct":true,"visible":false},{"text":"Utricle","correct":false,"visible":false},{"text":"Endolymphatic duct","correct":false,"visible":false}]},{"id":1935,"text":"Due to the interruption of an optic tract, the field of vision on one side of each eye is affected. What is this condition called?","explanation":null,"reference":"Chung KW, Chung HM, Halliday NL. BRS: Gross Anatomy. 8th ed. Wolters Kluwer Health; 2015: 383.","responses":[{"text":"Heteronymous hemianopsia","correct":false,"visible":false},{"text":"Bitemporal hemianopsia","correct":false,"visible":false},{"text":"Unilateral hemianopsia","correct":false,"visible":false},{"text":"Homonymous hemianopsia","correct":true,"visible":false},{"text":"Binasal hemianopsia","correct":false,"visible":false}]},{"id":1936,"text":"During a discussion, a teacher says that the given fossa has communication with the middle cranial fossa, orbital cavity, oral cavity, nasal cavity, and the foramen lacerum. Which of the following fossa is being discussed?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 981.","responses":[{"text":"Infratemporal fossa","correct":false,"visible":false},{"text":"Anterior cranial fossa","correct":false,"visible":false},{"text":"Occipital fossa","correct":false,"visible":false},{"text":"Temporal fossa","correct":false,"visible":false},{"text":"Pterygopalatine fossa","correct":true,"visible":false}]},{"id":1937,"text":"Which of the following occurs during the pharyngeal stage of swallowing?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 798.","responses":[{"text":"Vocal cords approximated and larynx is pulled upwards","correct":true,"visible":false},{"text":"Respiration is stimulated","correct":false,"visible":false},{"text":"Larynx is pulled downwards","correct":false,"visible":false},{"text":"Vocal cords open","correct":false,"visible":false},{"text":"Epiglottis moves upwards","correct":false,"visible":false}]},{"id":1938,"text":"Extraocular muscles are supplied by nerves that pass through which of the following?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 854, 930.","responses":[{"text":"Foramen ovale","correct":false,"visible":false},{"text":"Optic canal","correct":false,"visible":false},{"text":"Inferior orbital fissure","correct":false,"visible":false},{"text":"Superior orbital fissure","correct":true,"visible":false},{"text":"Foramen spinosum","correct":false,"visible":false}]},{"id":1997,"text":"Which facial nerve branches are present in the middle ear?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 949.","responses":[{"text":"Chorda tympani and greater petrosal nerve","correct":false,"visible":false},{"text":"Chorda tympani and nerve to stapedius","correct":true,"visible":false},{"text":"Deep petrosal nerve","correct":false,"visible":false},{"text":"Vidian nerve","correct":false,"visible":false},{"text":"Greater petrosal nerve and nerve to stapedius","correct":false,"visible":false}]},{"id":2007,"text":"Which of the following arteries is not a branch of the external carotid artery?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1001, 1008.","responses":[{"text":"Superior thyroid artery","correct":false,"visible":false},{"text":"Facial","correct":false,"visible":false},{"text":"Inferior thyroid artery","correct":true,"visible":false},{"text":"Sphenopalatine artery","correct":false,"visible":false},{"text":"Occipital","correct":false,"visible":false}]},{"id":2011,"text":"Which structure does not take part in the formation of an external nose?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1060-1063.","responses":[{"text":"Maxillary bone","correct":false,"visible":false},{"text":"Nasal cartilages","correct":false,"visible":false},{"text":"Inferior conchae","correct":true,"visible":false},{"text":"All of these take part","correct":false,"visible":false},{"text":"Nasal bone","correct":false,"visible":false}]},{"id":2042,"text":"Which nerve supplies the general sensation for the anterior 2/3rd of the tongue?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1089.","responses":[{"text":"Hypoglossal","correct":false,"visible":false},{"text":"Maxillary","correct":false,"visible":false},{"text":"Lingual","correct":true,"visible":false},{"text":"Glossopharyngeal","correct":false,"visible":false},{"text":"Facial","correct":false,"visible":false}]},{"id":2066,"text":"The speech and tone are produced with the assistance of which of the following?","explanation":null,"reference":"1) Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 500-501.\r\n\r\n\r\n2) Siddiqui LH. Medical Histology Text And Atlas. 6th ed. Paramount; 2019: 170.","responses":[{"text":"Larynx","correct":false,"visible":false},{"text":"Tongue","correct":true,"visible":false},{"text":"Pharynx","correct":false,"visible":false},{"text":"Nasal cavity","correct":false,"visible":false},{"text":"Tonsils","correct":false,"visible":false}]},{"id":2097,"text":"Posterior 1/3rd of the tongue is supplied by which nerve?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1089.","responses":[{"text":"Glossopharyngeal nerve","correct":true,"visible":false},{"text":"Facial nerve","correct":false,"visible":false},{"text":"Olfactory nerve","correct":false,"visible":false},{"text":"Trigeminal nerve","correct":false,"visible":false},{"text":"Vagus nerve","correct":false,"visible":false}]},{"id":2121,"text":"Which of the following ions moves from endolymph to stereocilia to depolarize the hair cells?","explanation":"The ion that moves from the endolymph to the stereocilia of hair cells to depolarize them is **K+ (potassium ion)**.\r\n\r\nIn the inner ear, the sensory hair cells of the cochlea and vestibular system are responsible for converting mechanical vibrations into electrical signals that can be interpreted by the brain. This process involves the movement of ions, specifically potassium, to initiate depolarization and signal transmission.\r\n\r\nThe endolymph, which is the fluid within the cochlear and vestibular ducts, has a high concentration of potassium ions. When sound vibrations or head movements stimulate the stereocilia of the hair cells, the mechanotransduction channels open, allowing potassium ions to flow into the hair cells. This influx of potassium depolarizes the hair cells and triggers the release of neurotransmitters, initiating the transmission of auditory or balance signals to the brain.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 668.","responses":[{"text":"Mg2+","correct":false,"visible":false},{"text":"Cl-","correct":false,"visible":false},{"text":"Ca2+","correct":false,"visible":false},{"text":"K+","correct":true,"visible":false},{"text":"Na+","correct":false,"visible":false}]},{"id":2164,"text":"Which of the following is not a terminal branch of the seventh cranial nerve?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 901.","responses":[{"text":"Buccal","correct":false,"visible":false},{"text":"Marginal mandibular","correct":false,"visible":false},{"text":"Temporal","correct":false,"visible":false},{"text":"Ophthalmic","correct":true,"visible":false},{"text":"Zygomatic","correct":false,"visible":false}]},{"id":2165,"text":"Which of the following is true regarding the structure of taste buds?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 300.","responses":[{"text":"They are mainly located on the soft palate but few on the ventral surface of tongue","correct":false,"visible":false},{"text":"A taste bud consists of 10-12 cells","correct":false,"visible":false},{"text":"Sustentacular cells of taste buds are also known as gustatory cells","correct":false,"visible":false},{"text":"Apex of the taste buds communicate with the oral cavity through taste pore","correct":true,"visible":false},{"text":"Taste buds are embedded within epithelium covering the  filiform papillae","correct":false,"visible":false}]},{"id":2166,"text":"Hearing loss associated with aging is termed as which of the following?","explanation":null,"reference":"Fischer N, Weber B, Riechelmann H. [presbycusis - age related hearing loss]. Laryngo- Rhino- Otologie. Published July 2016. https://pubmed.ncbi.nlm.nih.gov/27392191/","responses":[{"text":"Otitis media","correct":false,"visible":false},{"text":"Presbycusis","correct":true,"visible":false},{"text":"Conductive deafness","correct":false,"visible":false},{"text":"Sensorineural hearing loss","correct":false,"visible":false},{"text":"Ménière's disease","correct":false,"visible":false}]},{"id":2167,"text":"If the head is rotated to indicate a 'no' response, the movement occurs at which of the following joint?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 19.","responses":[{"text":"Atlantooccipital joint","correct":false,"visible":false},{"text":"C2-C3 joint","correct":false,"visible":false},{"text":"C3-C4 joint","correct":false,"visible":false},{"text":"Atlantoaxial joint","correct":true,"visible":false},{"text":"C7-T1 joint","correct":false,"visible":false}]},{"id":2168,"text":"In the case of vitamin A deficiency, keratomalacia occurs. Which of the following characterizes this condition?","explanation":"Keratomalacia is a condition characterized by **dryness and clouding of the cornea** due to severe **vitamin A deficiency**. Vitamin A is essential for maintaining the integrity and health of the epithelial tissues, including the **cornea**. The cornea is the clear, outermost layer of the eye that plays a crucial role in **focusing light onto the retina** for vision.\r\n\r\nIn vitamin A deficiency, the lack of this important nutrient leads to a disruption in the normal functioning of the **epithelial cells in the cornea**. The cornea becomes **dry, loses its clarity**, and may develop **ulcers or other abnormalities**. This can result in vision impairment, including **night blindness (nyctalopia)** and eventually, if left untreated, **complete blindness**.\r\n\r\nThe term \"keratomalacia\" specifically refers to the **softening and degeneration of the cornea** due to vitamin A deficiency. The condition is often associated with other systemic manifestations of vitamin A deficiency, such as **xerophthalmia (dryness of the conjunctiva)** and **Bitot's spots (localized thickening of the conjunctiva)**. Prompt treatment with **vitamin A supplementation** can reverse the ocular manifestations of keratomalacia and prevent further vision loss.","reference":"Chan E, Buzzard J, Helms R, Grigorian AP. Evaluation and clinical course of keratomalacia with descemetocele in a child with autism and vitamin a deficiency. Journal of Pediatric Ophthalmology \u0026 Strabismus. Published November 2020. Accessed April 25, 2022. https://www.ncbi.nlm.nih.gov/medgen/57777","responses":[{"text":"Localized thickening of conjunctiva","correct":false,"visible":false},{"text":"Dryness of conjunctiva and cornea","correct":false,"visible":false},{"text":"Unable to see in light or dark condition","correct":false,"visible":false},{"text":"Patient cannot see in low light or in near dark condition","correct":false,"visible":false},{"text":"Dryness and clouding of cornea","correct":true,"visible":false}]},{"id":2170,"text":"A colorblind person, who is a protanope, lacks which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 646.","responses":[{"text":"Rhodopsin","correct":false,"visible":false},{"text":"Green cones","correct":false,"visible":false},{"text":"Blue cones","correct":false,"visible":false},{"text":"Red cones","correct":true,"visible":false},{"text":"White cones","correct":false,"visible":false}]},{"id":2171,"text":"In the process of light adaptation which of the following events occurs?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 644.","responses":[{"text":"The level of rhodopsin is high","correct":false,"visible":false},{"text":"Bipolar cells transmit signals at the maximum rate","correct":false,"visible":false},{"text":"Photochemicals in photoreceptors are reduced to retinal and opsin","correct":true,"visible":false},{"text":"Vitamin A is converted into retinal","correct":false,"visible":false},{"text":"The size of pupil is increased","correct":false,"visible":false}]},{"id":2173,"text":"The intermediate column of the spinal cord gives rise to which of the following?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 58.","responses":[{"text":"Marginal layer","correct":false,"visible":false},{"text":"Posterior grey horn","correct":false,"visible":false},{"text":"Anterior grey horn","correct":false,"visible":false},{"text":"Mantle layer","correct":false,"visible":false},{"text":"Lateral grey horn","correct":true,"visible":false}]},{"id":2174,"text":"Investing layer of the deep fascia of the neck encloses which of the following?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 990.","responses":[{"text":"Digastric","correct":false,"visible":false},{"text":"Genohyoid","correct":false,"visible":false},{"text":"Mylohyoid","correct":false,"visible":false},{"text":"Omohyoid","correct":false,"visible":false},{"text":"Sternocleidomastoid","correct":true,"visible":false}]},{"id":2176,"text":"The major site of a nose bleed is the anterior region of the medial wall of the nasal cavity. Which of the following arteries does not participate in the anastomosis at that site?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1073.","responses":[{"text":"Branches from sphenopalatine artery","correct":false,"visible":false},{"text":"Branches of lesser palatine artery","correct":true,"visible":false},{"text":"Branches of anterior ethmoidal artery","correct":false,"visible":false},{"text":"Branches of greater palatine artery","correct":false,"visible":false},{"text":"Branches from superior labial artery","correct":false,"visible":false}]},{"id":2177,"text":"The middle ear cavity is present in which of the following bones?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 942.","responses":[{"text":"Mastoid bone","correct":false,"visible":false},{"text":"Sphenoid bone","correct":false,"visible":false},{"text":"Temporal bone","correct":true,"visible":false},{"text":"Occipital bone","correct":false,"visible":false},{"text":"Greater wing of sphenoid","correct":false,"visible":false}]},{"id":2178,"text":"The middle meningeal artery passes through which of the following?","explanation":null,"reference":null,"responses":[{"text":"Foramen ovale","correct":false,"visible":false},{"text":"Foramen rotundum","correct":false,"visible":false},{"text":"Foramen lacerum","correct":false,"visible":false},{"text":"Superior orbital fissure","correct":false,"visible":false},{"text":"Foramen  spinosum","correct":true,"visible":false}]},{"id":2181,"text":"Most of the refraction of light occurs in the eyes at which site?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 630.","responses":[{"text":"Anterior surface of cornea","correct":true,"visible":false},{"text":"Anterior surface of lens","correct":false,"visible":false},{"text":"Posterior surface of lens","correct":false,"visible":false},{"text":"Anterior surface of sclera","correct":false,"visible":false},{"text":"Posterior surface of cornea","correct":false,"visible":false}]},{"id":2182,"text":"Cricothyroid, a muscle of the larynx develops from which of the following pharyngeal arches?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 159.","responses":[{"text":"Mandibular arch","correct":false,"visible":false},{"text":"Hyoid arch","correct":false,"visible":false},{"text":"Sixth pharyngeal arch","correct":false,"visible":false},{"text":"Fourth pharyngeal arch","correct":true,"visible":false},{"text":"Fifth pharyngeal arch","correct":false,"visible":false}]},{"id":2183,"text":"Sensory innervation of laryngopharynx is by which of the following?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1040.","responses":[{"text":"External laryngeal nerve","correct":false,"visible":false},{"text":"Recurrent laryngeal nerve","correct":false,"visible":false},{"text":"Internal branch of superior laryngeal nerve","correct":true,"visible":false},{"text":"Pharyngeal branch of maxillary nerve","correct":false,"visible":false},{"text":"Glossopharyngeal nerve","correct":false,"visible":false}]},{"id":2184,"text":"Which of the following muscles of the middle ear is supplied by the facial nerve?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 884.","responses":[{"text":"Posterior auricular","correct":false,"visible":false},{"text":"Superior auricular","correct":false,"visible":false},{"text":"Anterior auricular","correct":false,"visible":false},{"text":"Stapedius","correct":true,"visible":false},{"text":"Tensor tympani","correct":false,"visible":false}]},{"id":2190,"text":"Which of the following is incorrect about salivary glands?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 329, 332.","responses":[{"text":"Serous cell are predominant cells of submandibular gland","correct":false,"visible":false},{"text":"Intercalated ducts are wider and longer in the parotid gland","correct":false,"visible":false},{"text":"All minor salivary gland are not encapsulated","correct":false,"visible":false},{"text":"All minor salivary glands are serous in nature","correct":true,"visible":false},{"text":"Demilune cells secrete lysozyme in sublingual gland","correct":false,"visible":false}]},{"id":2195,"text":"The auditory ossicle(s) attached to the oval window is/are derived from which of the following?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 159.","responses":[{"text":"Mandibular arch","correct":false,"visible":false},{"text":"3rd pharyngeal arch","correct":false,"visible":false},{"text":"4th pharyngeal arch","correct":false,"visible":false},{"text":"Hyoid arch","correct":true,"visible":false},{"text":"1st pharyngeal arch","correct":false,"visible":false}]},{"id":2196,"text":"Where are the infrahyoid muscles present?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 997.","responses":[{"text":"Submental triangle","correct":false,"visible":false},{"text":"Muscular triangle","correct":true,"visible":false},{"text":"Submandibular triangle","correct":false,"visible":false},{"text":"Posterior triangle","correct":false,"visible":false},{"text":"Carotid triangle","correct":false,"visible":false}]},{"id":2198,"text":"Sensory retina develops from which part of the optic cup?","explanation":"The sensory retina develops from the **Pars optica retinae** of the optic cup.\r\n\r\nDuring embryonic development, the optic cup forms from the optic vesicle, which is an outpouching of the neural tube. The optic cup consists of two layers: the outer pigmented layer and the inner neural layer. The inner neural layer of the optic cup differentiates into the sensory retina.\r\n\r\nThe Pars optica retinae, also known as the optic cup proper, refers to the anterior portion of the neural layer of the optic cup. This region gives rise to the sensory retina, which contains the photoreceptor cells (rods and cones) responsible for detecting light and initiating the visual signaling process.\r\n\r\nThe sensory retina plays a critical role in vision by capturing and processing visual stimuli before transmitting them to the brain via the optic nerve.","reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 362.","responses":[{"text":"Pars optica retinae","correct":true,"visible":false},{"text":"Pars caeca retinae","correct":false,"visible":false},{"text":"Pars iridica retinae","correct":false,"visible":false},{"text":"Outer layer of the optic cup","correct":false,"visible":false},{"text":"Pars ciliaris retinae","correct":false,"visible":false}]},{"id":2202,"text":"Which of the following cells mainly causes lateral inhibition?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 648.","responses":[{"text":"Ganglionic cells","correct":false,"visible":false},{"text":"Amacrine cells","correct":false,"visible":false},{"text":"Horizontal cells","correct":true,"visible":false},{"text":"Rods","correct":false,"visible":false},{"text":"Bipolar cells","correct":false,"visible":false}]},{"id":2203,"text":"What substance combines with scotopsin to form rhodopsin?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 641.","responses":[{"text":"11-cis retinol","correct":false,"visible":false},{"text":"11-cis retinal","correct":true,"visible":false},{"text":"All-trans retinol","correct":false,"visible":false},{"text":"13-cis retinol","correct":false,"visible":false},{"text":"All-trans retinal","correct":false,"visible":false}]},{"id":2230,"text":"Nightmares occur mostly during which sleep?","explanation":null,"reference":"1) Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 753.\r\n\r\n2) Simor P, Bódizs R, Horváth K, Ferri R. Disturbed dreaming and the instability of sleep: altered nonrapid eye movement sleep microstructure in individuals with frequent nightmares as revealed by the cyclic alternating pattern. Sleep. Published March 1, 2013. Accessed April 25, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3571751/","responses":[{"text":"REM sleep","correct":true,"visible":false},{"text":"NREM -2  sleep","correct":false,"visible":false},{"text":"Stage of drowsiness","correct":false,"visible":false},{"text":"NREM -3 sleep","correct":false,"visible":false},{"text":"NREM -1 sleep","correct":false,"visible":false}]},{"id":2231,"text":"An oblique facial cleft is a developmental anomaly that occurs due to failure of fusion of which of the following structures?","explanation":"An oblique facial cleft is a developmental anomaly that occurs due to the failure of fusion between the **maxillary prominence** and the **lateral nasal prominence**. During embryonic development, the face forms through the fusion of various facial prominences, which are bulges of tissue that grow and come together. The maxillary prominence is an important component of the developing face and contributes to the formation of the upper jaw and the sides of the upper lip. The lateral nasal prominence, on the other hand, gives rise to the sides of the nose.\r\n\r\nIn cases of an oblique facial cleft, there is a visible separation or gap between the maxillary and lateral nasal prominences, resulting in a cleft or fissure in the affected area of the face. This anomaly can vary in severity, ranging from a small notch or groove to a more significant cleft extending through the lip and possibly into the palate.","reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 306.","responses":[{"text":"Two medial nasal prominence with each other","correct":false,"visible":false},{"text":"Two maxillary prominence with each other","correct":false,"visible":false},{"text":"Two mandibular prominence with each other","correct":false,"visible":false},{"text":"Maxillary prominence with lateral nasal prominence","correct":true,"visible":false},{"text":"Maxillary prominence with medial nasal prominence","correct":false,"visible":false}]},{"id":2232,"text":"The olfactory epithelium is located at which site in the nasal cavity?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 349-350.","responses":[{"text":"Inferior portion of the nasal cavity","correct":false,"visible":false},{"text":"It is not present in the nasal cavity","correct":false,"visible":false},{"text":"Posterior and lateral portion of nasal cavity","correct":false,"visible":false},{"text":"Anterior and lateral portion of nasal cavity","correct":false,"visible":false},{"text":"Superior portion of nasal cavity","correct":true,"visible":false}]},{"id":2234,"text":"Piriform aperture is bounded by which of the following bones?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 844.","responses":[{"text":"Nasal bones and maxilla","correct":true,"visible":false},{"text":"Maxillary and zygomatic bones","correct":false,"visible":false},{"text":"Lacrimal and nasal bones","correct":false,"visible":false},{"text":"Nasal and zygomatic bones","correct":false,"visible":false},{"text":"Frontal and nasal bones","correct":false,"visible":false}]},{"id":2235,"text":"Pterygoid venous plexus is a network of veins that drains into which of the following vein?","explanation":"The pterygoid venous plexus is a network of veins that drains into the **maxillary vein**.\r\n\r\nThe pterygoid venous plexus is located in the pterygopalatine fossa, which is a small space in the skull behind the maxilla and lateral to the nasal cavity. It is formed by an intricate network of veins that communicate with each other and receive blood from various regions of the face and cranial cavity.\r\n\r\nThe veins of the pterygoid venous plexus drain into multiple venous channels, one of which is the **maxillary vein**. The maxillary vein is a major vein that accompanies the maxillary artery in the infratemporal fossa. It receives blood from the pterygoid venous plexus, as well as other veins in the region, and ultimately contributes to the venous drainage of the face.","reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1107.","responses":[{"text":"Maxillary vein","correct":true,"visible":false},{"text":"Inferior ophthalmic vein","correct":false,"visible":false},{"text":"Superior ophthalmic vein","correct":false,"visible":false},{"text":"Facial vein","correct":false,"visible":false},{"text":"Cavernous sinus","correct":false,"visible":false}]},{"id":2238,"text":"The parafollicular cells (C-cells) of the thyroid are derived from which of the following?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 163-164.","responses":[{"text":"Second pharyngeal pouch","correct":false,"visible":false},{"text":"Third pharyngeal arch","correct":false,"visible":false},{"text":"First pharyngeal pouch","correct":false,"visible":false},{"text":"Ultimobranchial body","correct":true,"visible":false},{"text":"Second pharyngeal cleft","correct":false,"visible":false}]},{"id":2240,"text":"Which of the following is true regarding the retromandibular vein?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 993.","responses":[{"text":"It is formed anterior to the ear by the union of the superficial temporal and maxillary veins","correct":true,"visible":false},{"text":"It joins with the common facial vein to form external jugular vein","correct":false,"visible":false},{"text":"It drains the side of head and superficial aspects of temporal muscles","correct":false,"visible":false},{"text":"It ultimately drains into internal jugular vein","correct":false,"visible":false},{"text":"It is formed posterior to the ear by the union of the superficial temporal and maxillary veins","correct":false,"visible":false}]},{"id":2243,"text":"Which of the following regarding mucous membrane of the tongue is incorrect?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 281, 298.","responses":[{"text":"Posterior one third of tongue is irregular with lymphoid aggregations called lingual tonsils","correct":false,"visible":false},{"text":"It is firmly bound to underlying muscle","correct":false,"visible":false},{"text":"Anterior two third of tongue is covered by small projections called papillae","correct":false,"visible":false},{"text":"It is loosely bound to underlying muscle","correct":true,"visible":false},{"text":"Ventral surface of tongue is covered by a smooth mucosa","correct":false,"visible":false}]},{"id":2245,"text":"Which of the following is the correct change in the photochemical process occurring due to absorption of light by rhodopsin?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 642.","responses":[{"text":"All-trans retinol to all-trans retinal","correct":false,"visible":false},{"text":"Metarhodopsin to bathorhodopsin","correct":false,"visible":false},{"text":"Lumirhodopsin to metarhodopsin","correct":true,"visible":false},{"text":"Bathorhodopsin to rhodopsin","correct":false,"visible":false},{"text":"Lumirhodopsin to bathorhodopsin","correct":false,"visible":false}]},{"id":2249,"text":"Which of the following is the sensory unit of the organ of Corti?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 664.","responses":[{"text":"Perilymph","correct":false,"visible":false},{"text":"Spiral ganglion","correct":false,"visible":false},{"text":"Basal membrane","correct":false,"visible":false},{"text":"Hair cells","correct":true,"visible":false},{"text":"Endolymph","correct":false,"visible":false}]},{"id":2254,"text":"The swallowing center is located in which of the following?","explanation":"The swallowing center is located in the **medulla oblongata**.\r\n\r\nThe medulla oblongata is the lowest part of the brainstem, connecting the brain to the spinal cord. It plays a crucial role in controlling many vital functions, including respiration, blood pressure regulation, and swallowing.\r\n\r\nWithin the medulla oblongata, there is a specialized region called the **swallowing center**. This center coordinates the complex series of muscle contractions and movements involved in the process of swallowing, also known as deglutition. The swallowing center receives sensory input from various sources, including the oral cavity and pharynx, and coordinates the sequential activation of the muscles involved in swallowing.\r\n\r\nDamage or dysfunction of the swallowing center in the medulla can lead to swallowing difficulties, known as dysphagia.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 798.","responses":[{"text":"Hypothalamus","correct":false,"visible":false},{"text":"Pons","correct":false,"visible":false},{"text":"Cerebellum","correct":false,"visible":false},{"text":"Midbrain","correct":false,"visible":false},{"text":"Medulla oblongata","correct":true,"visible":false}]},{"id":2257,"text":"Taste buds of vallate papillae are most sensitive to which taste?","explanation":null,"reference":"1) Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 676.\r\n2) Head and neck module, Physiology lecture slides, Topic: Sense of taste, Sub-topic: Taste receptors distribution.","responses":[{"text":"Umami","correct":false,"visible":false},{"text":"Sour","correct":false,"visible":false},{"text":"Sweet","correct":false,"visible":false},{"text":"Salty","correct":false,"visible":false},{"text":"Bitter","correct":true,"visible":false}]},{"id":2261,"text":"Which nucleus in the brainstem receives fibers carrying taste sensations?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 678.","responses":[{"text":"Dorsal nuclei","correct":false,"visible":false},{"text":"Nucleus ambiguus","correct":false,"visible":false},{"text":"Nucleus of pneumotaxic centre","correct":false,"visible":false},{"text":"Vasomotor centre","correct":false,"visible":false},{"text":"Nucleus of tractus solitarius","correct":true,"visible":false}]},{"id":2263,"text":"Tensor tympani is supplied by which of the following nerve?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 883.","responses":[{"text":"Mandibular nerve","correct":true,"visible":false},{"text":"Vestibulocochlear nerve","correct":false,"visible":false},{"text":"Facial nerve","correct":false,"visible":false},{"text":"Glossopharyngeal nerve","correct":false,"visible":false},{"text":"Maxillary nerve","correct":false,"visible":false}]},{"id":2264,"text":"Which is true regarding the venous drainage of face?","explanation":null,"reference":"1) Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 866.\r\n\r\n2) Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 908-909.","responses":[{"text":"Facial vein communicates with inferior ophthalmic vein","correct":false,"visible":false},{"text":"Facial vein drains into external jugular vein","correct":false,"visible":false},{"text":"Facial vein has unidirectional valves","correct":false,"visible":false},{"text":"Facial vein communicates with cavernous sinus through angular vein","correct":false,"visible":false},{"text":"Deep facial vein drains into the pterygoid plexus","correct":true,"visible":false}]},{"id":2268,"text":"The axons of ganglionic cells transmitting action potential synapse in the midbrain with which of the following structure?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 659.","responses":[{"text":"Inferior colliculus","correct":false,"visible":false},{"text":"Optic radiation","correct":false,"visible":false},{"text":"Superior colliculus","correct":true,"visible":false},{"text":"Lateral geniculate body","correct":false,"visible":false},{"text":"Medial geniculate body","correct":false,"visible":false}]},{"id":2271,"text":"Which of the following extrinsic muscles of the tongue is attached to the body of mandible?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1085-1087.","responses":[{"text":"Hyoglossus","correct":false,"visible":false},{"text":"Geniohyoid","correct":false,"visible":false},{"text":"Styloglossus","correct":false,"visible":false},{"text":"Palatoglossus","correct":false,"visible":false},{"text":"Genioglossus","correct":true,"visible":false}]},{"id":2274,"text":"The facial primordial appearance depends on the inductive influence of which of the following?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 174.","responses":[{"text":"Prosencephalic organizing centre","correct":true,"visible":false},{"text":"Neural tube","correct":false,"visible":false},{"text":"Notochord","correct":false,"visible":false},{"text":"Mesencephalic organizing centre","correct":false,"visible":false},{"text":"Stomodeum","correct":false,"visible":false}]},{"id":2277,"text":"Which of the following nerve does not supply sensory innervation to the face?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 903-905.","responses":[{"text":"Deep temporal nerve","correct":true,"visible":false},{"text":"Buccal nerve","correct":false,"visible":false},{"text":"Supratrochlear nerve","correct":false,"visible":false},{"text":"Supraorbital nerve","correct":false,"visible":false},{"text":"Zygomaticofacial nerve","correct":false,"visible":false}]},{"id":2278,"text":"Which of the following statements is true regarding the scalp?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 911-912.","responses":[{"text":"Wounds do not bleed easily","correct":false,"visible":false},{"text":"Blood vessels and nerves lie in  loose areolar tissue","correct":false,"visible":false},{"text":"Infections can easily spread through emissary veins into the cranial cavity","correct":true,"visible":false},{"text":"Wounds gape when injury is superficial to aponeurosis","correct":false,"visible":false},{"text":"Bleeding beneath periosteum extends through whole length of scalp","correct":false,"visible":false}]},{"id":2280,"text":"The infraorbital foramen is an opening in which of the following bones?","explanation":"The **infraorbital foramen** is an opening in the **maxillary bone**. It is located in the floor of the orbit, just below the infraorbital margin. The foramen serves as a passageway for the **infraorbital nerve**, which is a branch of the **maxillary division** of the trigeminal nerve (CN V2). The infraorbital nerve provides sensory innervation to the lower eyelid, upper lip, and lateral aspect of the nose.","reference":"Drake RL, Vogl W, Mitchell AWM, Gray H. Gray’s Anatomy for Students. 3rd ed. Churchill Livingstone/Elsevier; 2015: 856.","responses":[{"text":"Ethmoid bone","correct":false,"visible":false},{"text":"Zygomatic bone","correct":false,"visible":false},{"text":"Greater wing of the sphenoid bone","correct":false,"visible":false},{"text":"Frontal bone","correct":false,"visible":false},{"text":"Maxillary bone","correct":true,"visible":false}]},{"id":2283,"text":"Which of the following ion is responsible for the depolarization of olfactory receptor cells after their binding with the odor molecule?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 679.","responses":[{"text":"K+ ion","correct":false,"visible":false},{"text":"Cl- ion","correct":false,"visible":false},{"text":"Na+ ion","correct":true,"visible":false},{"text":"H+ ion","correct":false,"visible":false},{"text":"Ca+2 ion","correct":false,"visible":false}]},{"id":2284,"text":"The nasolacrimal duct opens into which of the following?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 901.","responses":[{"text":"Infundibulum","correct":false,"visible":false},{"text":"Superior meatus","correct":false,"visible":false},{"text":"Hiatus semilunaris","correct":false,"visible":false},{"text":"Spheno-ethmoidal recess","correct":false,"visible":false},{"text":"Inferior meatus","correct":true,"visible":false}]},{"id":2286,"text":"Which of the following muscles is not supplied by the mandibular nerve?","explanation":"The **buccinator muscle** is not supplied by the **mandibular nerve** (CN V3). The buccinator muscle is innervated by the **facial nerve** (CN VII). The buccinator muscle forms the lateral wall of the oral cavity and plays a role in mastication by keeping the cheeks taut.\r\n\r\nThe other muscles listed in the options, namely the **lateral pterygoid, temporalis, masseter**, and **medial pterygoid**, are all supplied by the mandibular nerve (CN V3). The mandibular nerve is the largest branch of the trigeminal nerve and provides motor innervation to the muscles of mastication.","reference":"Drake RL, Vogl W, Mitchell AWM, Gray H. Gray’s Anatomy for Students. 3rd ed. Churchill Livingstone/Elsevier; 2015: 977.","responses":[{"text":"Temporalis","correct":false,"visible":false},{"text":"Buccinator","correct":true,"visible":false},{"text":"Medial pterygoid","correct":false,"visible":false},{"text":"Masseter","correct":false,"visible":false},{"text":"Lateral pterygoid","correct":false,"visible":false}]},{"id":2287,"text":"Which neurotransmitter is released by rods and cones in their synapse with bipolar cells?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 647.","responses":[{"text":"Acetylcholine","correct":false,"visible":false},{"text":"Glycine","correct":false,"visible":false},{"text":"Dopamine","correct":false,"visible":false},{"text":"Serotonin","correct":false,"visible":false},{"text":"Glutamate","correct":true,"visible":false}]},{"id":2288,"text":"The primary palate forms which of the following structures?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 182.","responses":[{"text":"Soft palate","correct":false,"visible":false},{"text":"Upper jaw","correct":false,"visible":false},{"text":"Hard palate anterior to the incisive fossa","correct":true,"visible":false},{"text":"Hard palate","correct":false,"visible":false},{"text":"Lateral palatine process","correct":false,"visible":false}]},{"id":2291,"text":"The refractive power of the lens is expressed in which of the following units?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 629.","responses":[{"text":"Hertz","correct":false,"visible":false},{"text":"Diopters","correct":true,"visible":false},{"text":"Microns","correct":false,"visible":false},{"text":"Dynes","correct":false,"visible":false},{"text":"Decibels","correct":false,"visible":false}]},{"id":2292,"text":"Which of the following is the relation of the facial nerve with the parotid gland?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 923.","responses":[{"text":"Deep to gland","correct":false,"visible":false},{"text":"Superficial to artery","correct":false,"visible":false},{"text":"Deep to arteries","correct":false,"visible":false},{"text":"Superficial to gland","correct":false,"visible":false},{"text":"Superficial to vein","correct":true,"visible":false}]},{"id":2294,"text":"What is the relation of the retromandibular vein with the parotid gland?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 923.","responses":[{"text":"Superficial to the facial artery","correct":false,"visible":false},{"text":"Deep to the facial artery","correct":false,"visible":false},{"text":"Deep to the gland","correct":true,"visible":false},{"text":"Superficial to gland","correct":false,"visible":false},{"text":"Superficial to facial nerve","correct":false,"visible":false}]},{"id":2295,"text":"The six extraocular muscles are supplied by which of the following nerves?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 929.","responses":[{"text":"Olfactory and oculomotor nerve","correct":false,"visible":false},{"text":"Abducent nerve","correct":false,"visible":false},{"text":"Trochlear and facial nerve","correct":false,"visible":false},{"text":"Oculomotor, trochlear, and abducent nerve","correct":true,"visible":false},{"text":"Trigeminal and facial nerve","correct":false,"visible":false}]},{"id":2298,"text":"The triangular primary palate is formed by the fusion of which of the following?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 182.","responses":[{"text":"Medial nasal prominence","correct":true,"visible":false},{"text":"Maxillary prominence with lateral nasal prominence","correct":false,"visible":false},{"text":"Two lateral nasal prominence","correct":false,"visible":false},{"text":"Two maxillary prominence","correct":false,"visible":false},{"text":"Two mandibular prominence","correct":false,"visible":false}]},{"id":2301,"text":"Which of the following structures does not originate from the utricular portion of the otic vesicle?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 428.","responses":[{"text":"Endolymphatic duct","correct":false,"visible":false},{"text":"Semicircular canals","correct":false,"visible":false},{"text":"Cochlear duct","correct":true,"visible":false},{"text":"Endolymphatic sac","correct":false,"visible":false},{"text":"Utricle","correct":false,"visible":false}]},{"id":2302,"text":"Visual fibers also pass through the pretectal nucleus in the midbrain. Pretectal nucleus is associated with which of the following function?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 653.","responses":[{"text":"Pupillary light reflex","correct":true,"visible":false},{"text":"Attenuation reflex","correct":false,"visible":false},{"text":"Balance and equilibrium","correct":false,"visible":false},{"text":"Color sensation","correct":false,"visible":false},{"text":"Accommodation reflex","correct":false,"visible":false}]},{"id":2303,"text":"Visual pathway does not include which of the following?","explanation":null,"reference":"1) Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 653.\r\n\r\n2) Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 286.","responses":[{"text":"Optic nerve","correct":false,"visible":false},{"text":"Medial geniculate body","correct":true,"visible":false},{"text":"Cortical area 17","correct":false,"visible":false},{"text":"Optic tract","correct":false,"visible":false},{"text":"Optic chiasma","correct":false,"visible":false}]},{"id":2304,"text":"Which of the following nerves supplies the muscles of facial expression?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 891.","responses":[{"text":"Glossopharyngeal nerve","correct":false,"visible":false},{"text":"Facial nerve","correct":true,"visible":false},{"text":"Mandibular division of trigeminal nerve","correct":false,"visible":false},{"text":"Accessory nerve","correct":false,"visible":false},{"text":"Vagus nerve","correct":false,"visible":false}]},{"id":2305,"text":"Which muscle takes part in the formation of palatine aponeurosis?","explanation":"The **tensor veli palatini** muscle takes part in the formation of the palatine aponeurosis.\r\n\r\nThe palatine aponeurosis is a thin, fibrous sheet that extends horizontally across the posterior part of the hard palate. It plays a role in elevating the soft palate and closing off the nasopharynx during swallowing and speaking. The palatine aponeurosis is an important structure in maintaining the integrity of the soft palate and its proper functioning.\r\n\r\nThe tensor veli palatini muscle is one of the muscles involved in the soft palate's movement and function. It arises from the cartilaginous part of the auditory tube (eustachian tube) and the adjacent sphenoid bone. It courses downward and laterally to insert into the palatine aponeurosis. Contraction of the tensor veli palatini muscle helps to tense and flatten the soft palate, contributing to the closure of the nasopharynx during swallowing and speaking.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 946.","responses":[{"text":"Tensor tympani","correct":false,"visible":false},{"text":"Palatoglossus","correct":false,"visible":false},{"text":"Palatopharyngeus","correct":false,"visible":false},{"text":"Tensor veli palatini","correct":true,"visible":false},{"text":"Musculus uvulae","correct":false,"visible":false}]},{"id":2306,"text":"Which one of the following structures is not a content of the posterior triangle of the neck?","explanation":null,"reference":"Chung KW, Chung HM, Halliday NL. BRS: Gross Anatomy. 8th ed. Wolters Kluwer Health; 2015: 337-338.","responses":[{"text":"Trunks of brachial plexus","correct":false,"visible":false},{"text":"Cerebral plexus","correct":true,"visible":false},{"text":"Occipital lymph nodes","correct":false,"visible":false},{"text":"Subclavian artery","correct":false,"visible":false},{"text":"Accessory nerve","correct":false,"visible":false}]},{"id":2308,"text":"Which of the following is not a branch of the maxillary division of the trigeminal nerve?","explanation":null,"reference":"Chung KW, Chung HM, Halliday NL. BRS: Gross Anatomy. 8th ed. Wolters Kluwer Health; 2015: 410-411.","responses":[{"text":"Zygomaticofacial nerve","correct":false,"visible":false},{"text":"Supraorbital nerve","correct":true,"visible":false},{"text":"Infraorbital nerve","correct":false,"visible":false},{"text":"Posterior superior alveolar nerve","correct":false,"visible":false},{"text":"Zygomaticotemporal nerve","correct":false,"visible":false}]},{"id":2310,"text":"Which primary cortical sensory area is located in the middle of the superior temporal gyrus?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 670.","responses":[{"text":"Hearing","correct":true,"visible":false},{"text":"Smell","correct":false,"visible":false},{"text":"Vision","correct":false,"visible":false},{"text":"Touch","correct":false,"visible":false},{"text":"Taste","correct":false,"visible":false}]},{"id":2311,"text":"The infratemporal fossa communicates with the middle cranial fossa through which of the following foramen?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 963.","responses":[{"text":"Foramen ovale","correct":true,"visible":false},{"text":"Foramen rotundum","correct":false,"visible":false},{"text":"Greater palatine foramen","correct":false,"visible":false},{"text":"Stylomastoid foramen","correct":false,"visible":false},{"text":"Lesser palatine foramen","correct":false,"visible":false}]},{"id":2312,"text":"If the lingual nerve is damaged which of the following condition is likely to occur?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 975.","responses":[{"text":"Upper gingival sensations are lost","correct":false,"visible":false},{"text":"Taste sensation on posterior one third of tongue is lost","correct":false,"visible":false},{"text":"Tongue is deviated to the left","correct":false,"visible":false},{"text":"Flattening of palatoglossal arch occurs","correct":false,"visible":false},{"text":"Submandibular secretions are lost","correct":true,"visible":false}]},{"id":2320,"text":"Which of the following is incorrect regarding the lacrimal apparatus?","explanation":null,"reference":"1) Siddiqui LH. Medical Histology Text And Atlas. 6th ed. Paramount; 2019: 253.\r\n\r\n2) Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 921.","responses":[{"text":"Tears flow to the lacrimal puncta","correct":false,"visible":false},{"text":"Lacrimal glands drain into superficial parotid lymph nodes","correct":false,"visible":false},{"text":"Tears collect in the conjunctival fornix","correct":false,"visible":false},{"text":"Secretions produced are called tears","correct":false,"visible":false},{"text":"Lacrimal glands are of simple tubuloacinar type","correct":true,"visible":false}]},{"id":2322,"text":"A person injures his mandible (ramus) in an accident. Which boundary of the wall of the infratemporal fossa does it form?","explanation":"The mandible forms part of the **lateral wall** of the infratemporal fossa. The infratemporal fossa is a space located deep to the zygomatic arch and posterior to the maxilla. It is bounded by several structures, including the lateral pterygoid plate, the greater wing of the sphenoid bone, the ramus of the mandible, and the deep temporal fascia.","reference":"Drake RL, Vogl W, Mitchell AWM, Gray H. Gray’s Anatomy for Students. 3rd ed. Churchill Livingstone/Elsevier; 2015: 981.","responses":[{"text":"Posterior wall","correct":false,"visible":false},{"text":"Inferior wall","correct":false,"visible":false},{"text":"Medial wall","correct":false,"visible":false},{"text":"Anterior wall","correct":false,"visible":false},{"text":"Lateral wall","correct":true,"visible":false}]},{"id":2345,"text":"Which is not true about the retina?","explanation":null,"reference":"Siddiqui LH. Medical Histology Text And Atlas. 6th ed. Paramount; 2019: 247.","responses":[{"text":"It terminates at ora serrata","correct":false,"visible":false},{"text":"It is highly vascular","correct":false,"visible":false},{"text":"It is the photoreceptor layer","correct":false,"visible":false},{"text":"Two retinal layers can easily be detached","correct":false,"visible":false},{"text":"The innermost layer of the retina contains the rods and cones","correct":true,"visible":false}]},{"id":2364,"text":"Which of the following nerves provide sensory supply to the skin overlying the angle of the mandible?","explanation":"The **greater auricular nerve** provides sensory supply to the skin overlying the angle of the mandible. It is a branch of the cervical plexus, specifically arising from the second and third cervical spinal nerves (C2-C3). \r\n\r\nThe greater auricular nerve travels superficially along the posterior border of the sternocleidomastoid muscle and ascends towards the angle of the mandible. It innervates the skin overlying the lower part of the ear, the angle of the mandible, and the adjacent area of the parotid region.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 857.","responses":[{"text":"Mandibular branch of trigeminal nerve","correct":false,"visible":false},{"text":"Lesser occipital nerve","correct":false,"visible":false},{"text":"Greater occipital nerve","correct":false,"visible":false},{"text":"Maxillary branch of trigeminal nerve","correct":false,"visible":false},{"text":"Greater auricular nerve","correct":true,"visible":false}]},{"id":2365,"text":"A person presents with his right eye looking \"down and out\" with double vision (diplopia) when looking at the right. He has a lesion in which of the following nerves?","explanation":"The patient's presentation of the right eye being \"down and out\" with diplopia on right gaze suggests a **lesion of the right oculomotor nerve** (cranial nerve III). The oculomotor nerve innervates several extraocular muscles responsible for eye movements, including the superior rectus, medial rectus, inferior rectus, and inferior oblique muscles.\r\n\r\nA lesion of the oculomotor nerve can result in various deficits, including **drooping of the eyelid** (ptosis), **inability to move the eye medially** (limitation of adduction), and **downward deviation of the eye** (inferior displacement). These findings are consistent with the patient's \"down and out\" eye position and diplopia on right gaze.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 350, 351.","responses":[{"text":"Left trochlear nerve","correct":false,"visible":false},{"text":"Right trochlear nerve","correct":false,"visible":false},{"text":"Right oculomotor nerve","correct":true,"visible":false},{"text":"Left trigeminal nerve","correct":false,"visible":false},{"text":"Left oculomotor nerve","correct":false,"visible":false}]},{"id":2366,"text":"Vitamin A is stored in which of the following form?","explanation":null,"reference":"Schreiber R, Taschler U, Preiss-Landl K, Wongsiriroj N, Zimmermann R, Lass A. Retinyl ester hydrolases and their roles in vitamin A homeostasis. Biochimica et Biophysica Acta. Published January 2012. Accessed April 29, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC3242165/","responses":[{"text":"Retinyl esters","correct":true,"visible":false},{"text":"All trans retinoic acid","correct":false,"visible":false},{"text":"Retinal","correct":false,"visible":false},{"text":"Retinol","correct":false,"visible":false},{"text":"11-cis retinal","correct":false,"visible":false}]},{"id":2370,"text":"Passavant's ridge helps to close the nasopharyngeal isthmus during swallowing.Which muscle contracts to produce the passavant's ridge?","explanation":null,"reference":"Olszewska E, Woodson BT. Palatal anatomy for sleep apnea surgery. Laryngoscope Investigative Otolaryngology. Published February 2019. https://pubmed.ncbi.nlm.nih.gov/30828637/","responses":[{"text":"Fibers of pharyngeal muscles","correct":false,"visible":false},{"text":"Upper most fibers of palatopharyngeus","correct":true,"visible":false},{"text":"Fibers of tensor palatini","correct":false,"visible":false},{"text":"Fibers of levator palatini","correct":false,"visible":false},{"text":"Fibers of palatoglossus","correct":false,"visible":false}]},{"id":2371,"text":"Which of the following is true regarding the connections of pterygopalatine ganglion?","explanation":null,"reference":"Chung KW, Chung HM, Halliday NL. BRS: Gross Anatomy. 8th ed. Wolters Kluwer Health; 2015: 411.","responses":[{"text":"Parasympathetic root is derived from deep petrosal nerve","correct":false,"visible":false},{"text":"Secretomotor fibers from the sympathetic root supply the lacrimal gland and paranasal sinuses","correct":false,"visible":false},{"text":"The sensory or parasympathetic root of ganglion is formed by branches of glossopharyngeal nerve","correct":false,"visible":false},{"text":"Sympathetic root is derived from nerve of pterygoid canal","correct":true,"visible":false},{"text":"Sensory root comes from facial nerve","correct":false,"visible":false}]},{"id":2475,"text":"Which of the following is the only branch coming from the medial side of the external carotid artery?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 980.","responses":[{"text":"Facial artery","correct":false,"visible":false},{"text":"Ascending pharyngeal artery","correct":true,"visible":false},{"text":"Occipital artery","correct":false,"visible":false},{"text":"Superior thyroid artery","correct":false,"visible":false},{"text":"Lingual artery","correct":false,"visible":false}]},{"id":2477,"text":"According to the psychoanalytic theory, what is the phenomenon that occurs if an issue or conflict in a psychosexual stage remains unresolved?","explanation":null,"reference":"Lantz SE, Ray S. Freud developmental theory. In: StatPearls. StatPearls Publishing; 2022. Accessed May 6, 2022. http://www.ncbi.nlm.nih.gov/books/NBK557526/","responses":[{"text":"Expressiveness","correct":false,"visible":false},{"text":"Fixation","correct":true,"visible":false},{"text":"Neuroticism","correct":false,"visible":false},{"text":"Regression","correct":false,"visible":false},{"text":"Retentiveness","correct":false,"visible":false}]},{"id":2478,"text":"Which of the following muscles contributes to the formation of the floor of the submandibular triangle along with the hyoglossus muscle?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 1008.","responses":[{"text":"Omohyoid","correct":false,"visible":false},{"text":"Thyropharyngeus","correct":false,"visible":false},{"text":"Mylohyoid","correct":true,"visible":false},{"text":"Thyrohyoid","correct":false,"visible":false},{"text":"Sternohyoid","correct":false,"visible":false}]},{"id":2481,"text":"Which spinal nerve does not have an associated dermatome?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 51.","responses":[{"text":"C5","correct":false,"visible":false},{"text":"C2","correct":false,"visible":false},{"text":"C4","correct":false,"visible":false},{"text":"C1","correct":true,"visible":false},{"text":"T1","correct":false,"visible":false}]},{"id":2482,"text":"A 34-year-old man visits the hospital with the complaint of being unable to shrug his shoulder after an injury. Which of the following is affected?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 703, 844.","responses":[{"text":"Jugular foramen","correct":true,"visible":false},{"text":"Condyloid canal","correct":false,"visible":false},{"text":"Foramen magnum","correct":false,"visible":false},{"text":"Hypoglossal canal","correct":false,"visible":false},{"text":"Anterior cranial foramen","correct":false,"visible":false}]},{"id":2483,"text":"The medial nasal prominences form which of the following in the external nose?","explanation":null,"reference":null,"responses":[{"text":"Dorsum of the nose","correct":false,"visible":false},{"text":"Apex of the nose","correct":false,"visible":false},{"text":"Root of the nose","correct":false,"visible":false},{"text":"Ala of the nose","correct":false,"visible":false},{"text":"Ethmoid bone","correct":true,"visible":false}]},{"id":2486,"text":"An infection of the eustachian tube causes which of the following?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 746.","responses":[{"text":"Acute mastoiditis","correct":false,"visible":false},{"text":"Vestibular neuronitis","correct":false,"visible":false},{"text":"Presbycusis","correct":false,"visible":false},{"text":"Otitis media","correct":true,"visible":false},{"text":"Otitis externa","correct":false,"visible":false}]},{"id":2487,"text":"Activation of receptor by an odorant particle is by what mechanism?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 680.","responses":[{"text":"PI3 kinase","correct":false,"visible":false},{"text":"G protein complex","correct":true,"visible":false},{"text":"Ion channel","correct":false,"visible":false},{"text":"β subunit","correct":false,"visible":false},{"text":"Tyrosine complex","correct":false,"visible":false}]},{"id":2489,"text":"A lesion of the oculomotor nerve result in which of the following?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 350, 351.","responses":[{"text":"Esotropia","correct":false,"visible":false},{"text":"Pupillary contriction","correct":false,"visible":false},{"text":"Exotropia","correct":true,"visible":false},{"text":"Ciliary muscle spasm","correct":false,"visible":false},{"text":"Myopia","correct":false,"visible":false}]},{"id":2490,"text":"Which of the following does not supply the subcutaneous structures?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 51.","responses":[{"text":"C2","correct":false,"visible":false},{"text":"C4","correct":false,"visible":false},{"text":"C5","correct":false,"visible":false},{"text":"C3","correct":false,"visible":false},{"text":"C1","correct":true,"visible":false}]},{"id":2493,"text":"The submandibular lymph nodes are present in which triangle?","explanation":"The submandibular lymph nodes are located in the **digastric triangle**, also known as the submandibular triangle. This triangular region is formed by the anterior and posterior bellies of the digastric muscle and the inferior border of the mandible.\r\n\r\nThe submandibular lymph nodes are part of the lymphatic drainage system of the head and neck. They receive lymphatic vessels from various structures in the oral cavity, sublingual region, tongue, and submandibular gland. These nodes play a crucial role in filtering lymph fluid and trapping pathogens, foreign particles, and cancer cells.","reference":"Drake RL, Vogl W, Mitchell AWM, Gray H. Gray’s Anatomy for Students. 3rd ed. Churchill Livingstone/Elsevier; 2015: 1022.","responses":[{"text":"Muscular triangle","correct":false,"visible":false},{"text":"Omohyoid triangle","correct":false,"visible":false},{"text":"Carotid triangle","correct":false,"visible":false},{"text":"Digastric triangle","correct":true,"visible":false},{"text":"Submental triangle","correct":false,"visible":false}]},{"id":2494,"text":"Which of the following equalizes the pressure between the external atmosphere and the middle ear cavity?","explanation":"The **Eustachian tube** (also known as the auditory tube or pharyngotympanic tube) is responsible for equalizing the pressure between the external atmosphere and the middle ear cavity.\r\n\r\nThe Eustachian tube connects the middle ear cavity to the nasopharynx (the back of the throat). Its primary function is to regulate pressure in the middle ear, allowing the equalization of air pressure on both sides of the tympanic membrane (eardrum). \r\n\r\nDuring activities such as swallowing, yawning, or chewing, the Eustachian tube opens briefly, allowing air to flow in or out of the middle ear. This equalizes the pressure between the middle ear and the external atmosphere, preventing discomfort or distortion of sound perception. It also helps in maintaining the optimal functioning of the middle ear, including the movement of the ossicles (small bones) and transmission of sound vibrations.\r\n\r\nDysfunction or blockage of the Eustachian tube can lead to a feeling of ear fullness, muffled hearing, or even pain.","reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 946.","responses":[{"text":"External ear","correct":false,"visible":false},{"text":"Eustachian tube","correct":true,"visible":false},{"text":"Pinna","correct":false,"visible":false},{"text":"Tympanic membrane","correct":false,"visible":false},{"text":"Auricle","correct":false,"visible":false}]},{"id":2495,"text":"What happens to the vocal cords while swallowing?","explanation":"During swallowing, the vocal cords undergo a specific movement known as **approximation**. \r\n\r\nThe vocal cords, which are located within the larynx, play a crucial role in phonation (production of sound) and preventing the entry of food or liquid into the airway. When swallowing occurs, the vocal cords are brought together and tightly closed to form a protective barrier. This prevents the entry of food or liquid into the lower respiratory tract, ensuring that they pass down the esophagus instead.\r\n\r\nThe process of approximation is coordinated by the muscles of the larynx, particularly the **lateral cricoarytenoid muscles**. These muscles contract during swallowing, causing the vocal cords to move medially and come into contact with each other. This closure helps to seal off the entrance to the airway, maintaining airway protection during the swallowing process.\r\n\r\nOnce the swallowing is complete, the vocal cords return to their resting position and resume their role in vocalization.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 798.","responses":[{"text":"Opened","correct":false,"visible":false},{"text":"Overlapped","correct":false,"visible":false},{"text":"Approximated","correct":true,"visible":false},{"text":"No change","correct":false,"visible":false},{"text":"Gapped by membrane","correct":false,"visible":false}]},{"id":2497,"text":"A teacher discussed a fossa inferior and deep to the zygomatic arch and posterior to the maxilla. The appropriate fossa being discussed is?","explanation":"The **infratemporal fossa** is a complex anatomical region located deep within the skull, adjacent to the temporal bone. It is bordered by the zygomatic arch anteriorly, the maxilla and lateral pterygoid plate medially, the styloid process and mastoid process posteriorly, and the ramus of the mandible inferiorly. \r\n\r\nThis fossa contains various important structures, including the **mandibular nerve (branch of the trigeminal nerve)**, the **maxillary artery**, the **pterygoid muscles**, and the **inferior part of the temporalis muscle**. It serves as a conduit for the passage of neurovascular structures and plays a role in mastication (chewing) and jaw movement.","reference":"1) Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 826.\r\n\r\n\r\n\r\n2) Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 925.","responses":[{"text":"Infratemporal","correct":true,"visible":false},{"text":"Pterygopalatine","correct":false,"visible":false},{"text":"Occipital","correct":false,"visible":false},{"text":"Temporal","correct":false,"visible":false},{"text":"Middle cranial","correct":false,"visible":false}]},{"id":2498,"text":"The suspensory ligaments of the eye are an extension of which of the following?","explanation":"The suspensory ligaments of the eye, also known as the **suspensory ligament of the lens**, are extensions of **Tenon's capsule**. Tenon's capsule is a connective tissue layer that surrounds the eyeball and separates it from the surrounding orbital structures.\r\n\r\nThe suspensory ligaments play a crucial role in supporting and stabilizing the lens within the eye. They attach to the ciliary body, which is a muscular structure located just behind the iris. The ciliary body produces aqueous humor and contains the ciliary muscle, which is responsible for accommodation (changing the shape of the lens to focus on near or distant objects).\r\n\r\nBy connecting the lens to the ciliary body, the suspensory ligaments exert tension on the lens and help maintain its shape and position. They assist in the process of accommodation by allowing the ciliary muscle to alter the tension on the lens, enabling the eye to focus on objects at different distances.","reference":"Hu S, Colley P. Surgical orbital anatomy. Semin Plast Surg. 2019;33(2):85-91. doi:10.1055/s-0039-1685476\r\nhttps://www.ncbi.nlm.nih.gov/pmc/articles/PMC6486368","responses":[{"text":"Tenon's capsule","correct":true,"visible":false},{"text":"Periorbital fascia","correct":false,"visible":false},{"text":"Deep fascia","correct":false,"visible":false},{"text":"Orbital septum","correct":false,"visible":false},{"text":"Superficial fascia","correct":false,"visible":false}]},{"id":2499,"text":"Which of the following papillae are damaged if there is damage to the tongue anterior to the terminal sulcus?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 299-300.","responses":[{"text":"Foliate","correct":false,"visible":false},{"text":"Lingual","correct":false,"visible":false},{"text":"Fungiform","correct":false,"visible":false},{"text":"Circumvallate","correct":true,"visible":false},{"text":"Filiform","correct":false,"visible":false}]},{"id":2500,"text":"In which region are cristae found?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 516.","responses":[{"text":"Eustachian tube","correct":false,"visible":false},{"text":"Cochlea","correct":false,"visible":false},{"text":"Semicircular duct","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Tympanic cavity","correct":false,"visible":false}]},{"id":2501,"text":"The stereocilia of the hair cells of the organ of Corti are embedded in?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 667.","responses":[{"text":"Basilar membrane","correct":false,"visible":false},{"text":"Tympanic membrane","correct":false,"visible":false},{"text":"Tectorial membrane","correct":true,"visible":false},{"text":"Otolithic membrane","correct":false,"visible":false},{"text":"Reissner membrane","correct":false,"visible":false}]},{"id":2502,"text":"Prevertebral fascia forms the floor of which triangle?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1012.","responses":[{"text":"Muscular triangle","correct":false,"visible":false},{"text":"Omohyoid trianlge","correct":false,"visible":false},{"text":"Carotid triangle","correct":false,"visible":false},{"text":"Digastric triangle","correct":false,"visible":false},{"text":"Posterior triangle","correct":true,"visible":false}]},{"id":2504,"text":"A man received a strong blow to the anterior aspect of the mandible during a fight. The tympanic plate of the external auditory meatus was affected. The temporomandibular joint has undergone which type of dislocation?","explanation":"The TMJ is a synovial joint that allows for the movement of the mandible, enabling actions such as opening and closing the mouth, chewing, and speaking. It is formed by the articulation of the condyle of the mandible with the mandibular fossa of the temporal bone, along with the articular disc that separates the two bones.\r\n\r\nA **posterior dislocation** of the TMJ occurs when the mandibular condyle is forced posteriorly beyond the articular eminence of the temporal bone. This can happen due to a strong blow to the anterior aspect of the mandible, which causes the mandible to dislocate posteriorly.\r\n\r\nPatients with a posterior TMJ dislocation often present with the jaw locked in an open position and an inability to close the mouth. They may also experience pain and difficulty in moving the jaw.","reference":"Chung KW, Chung HM, Halliday NL. BRS: Gross Anatomy. 8th ed. Wolters Kluwer Health; 2015: 368.","responses":[{"text":"Medial","correct":false,"visible":false},{"text":"Anterior","correct":false,"visible":false},{"text":"Superior","correct":false,"visible":false},{"text":"Posterior","correct":true,"visible":false},{"text":"Lateral","correct":false,"visible":false}]},{"id":2505,"text":"A student is studying about a muscle that forms the boundaries of both anterior and posterior triangles. Which of the following is the appropriate muscle?","explanation":"The appropriate muscle that forms the boundaries of both the anterior and posterior triangles is the **sternocleidomastoid muscle**. This muscle is located in the neck and has a prominent position. It originates from the sternum and clavicle and inserts on the mastoid process of the temporal bone.\r\n\r\nThe sternocleidomastoid muscle divides the neck into two triangles: the anterior triangle and the posterior triangle. The anterior triangle is located in front of the muscle, while the posterior triangle is located behind it. These triangles serve as important anatomical landmarks in the neck.\r\n\r\nThe sternocleidomastoid muscle has multiple functions. It acts to flex and rotate the head, as well as elevate the sternum during forced inhalation. Additionally, it plays a role in maintaining proper posture.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 998.","responses":[{"text":"Sternocleidomastoid","correct":true,"visible":false},{"text":"Trapezius","correct":false,"visible":false},{"text":"Suprahyoid","correct":false,"visible":false},{"text":"Levator scapulae","correct":false,"visible":false},{"text":"Infrahyoid","correct":false,"visible":false}]},{"id":2507,"text":"Through which of the following structures light doesn't pass?","explanation":null,"reference":"Siddiqui LH. Medical Histology Text And Atlas. 6th ed. Paramount; 2019: 244.","responses":[{"text":"Lens","correct":false,"visible":false},{"text":"Vitreous body","correct":false,"visible":false},{"text":"Pupil","correct":false,"visible":false},{"text":"Cornea","correct":false,"visible":false},{"text":"Sclera","correct":true,"visible":false}]},{"id":2510,"text":"Which of the following statements is incorrect about the structures of the tongue?","explanation":null,"reference":"Siddiqui LH. Medical Histology Text And Atlas. 6th ed. Paramount; 2019: 170.","responses":[{"text":"It has a core of skeletal muscles","correct":false,"visible":false},{"text":"It has lymphoid aggregates called lymphoid tonsils","correct":false,"visible":false},{"text":"It is lined by stratified columnar epithelium","correct":true,"visible":false},{"text":"It has epithelial projections called papillae","correct":false,"visible":false},{"text":"Seromucous glands are present in the deep part of tongue","correct":false,"visible":false}]},{"id":2511,"text":"Which nucleus of the thalamus is responsible for carrying fibers to the auditory cortex?","explanation":"The nucleus of the thalamus that is responsible for carrying fibers to the auditory cortex is the **medial geniculate body**.\r\n\r\nThe auditory pathway involves the transmission of auditory information from the cochlea to the auditory cortex in the brain. After auditory signals are received by the cochlea, they are relayed through the cochlear nuclei in the brainstem. From there, the fibers ascend to the **medial geniculate body** located in the thalamus.\r\n\r\nThe medial geniculate body acts as a relay station for auditory information. It receives fibers from the cochlear nuclei and then projects these fibers to the auditory cortex, which is located in the temporal lobe of the brain. This pathway allows for the processing and interpretation of sound signals, contributing to our perception of hearing.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 669.","responses":[{"text":"Medial geniculate body","correct":true,"visible":false},{"text":"Dorsomedial nucleus","correct":false,"visible":false},{"text":"Lateral geniculate body","correct":false,"visible":false},{"text":"Ventroposteromedial nucleus","correct":false,"visible":false},{"text":"Venteroposterolateral nucleus","correct":false,"visible":false}]},{"id":2512,"text":"The pharyngeal plexus does not supply which of the following mucles?","explanation":null,"reference":"Drake RL, Vogl W, Mitchell AWM, Gray H. Gray’s Anatomy for Students. 3rd ed. Churchill Livingstone/Elsevier; 2015: 1051.","responses":[{"text":"Stylopharyngeus","correct":true,"visible":false},{"text":"Middle constrictor","correct":false,"visible":false},{"text":"Inferior constrictor","correct":false,"visible":false},{"text":"Palatopharyngeus","correct":false,"visible":false},{"text":"Superior constrictor","correct":false,"visible":false}]},{"id":2513,"text":"Striated ducts are not present in which of the following?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 333.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Parotid gland","correct":false,"visible":false},{"text":"Submandibular gland","correct":false,"visible":false},{"text":"Sublingual gland","correct":false,"visible":false},{"text":"Exocrine pancreas","correct":true,"visible":false}]},{"id":2514,"text":"In phototransduction, what happens in the presence of light?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 643.","responses":[{"text":"Increase in the number of open Na+ channels","correct":false,"visible":false},{"text":"Increased Ca+ conductance","correct":false,"visible":false},{"text":"Reduced cAMP and closed Na+ channel","correct":true,"visible":false},{"text":"Decreased phosphodiestearse activity","correct":false,"visible":false},{"text":"Decreased transducin activity","correct":false,"visible":false}]},{"id":2515,"text":"The sublingual gland produces which type of secretions?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 332.","responses":[{"text":"Predominantly serous","correct":false,"visible":false},{"text":"Seromucous","correct":false,"visible":false},{"text":"Serous","correct":false,"visible":false},{"text":"Mucous","correct":false,"visible":false},{"text":"Predominantly mucous","correct":true,"visible":false}]},{"id":2516,"text":"What term describes the lens of the eye becoming less elastic with the passage of time?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 631.","responses":[{"text":"Anosmia","correct":false,"visible":false},{"text":"Aguesia","correct":false,"visible":false},{"text":"Presbyopia","correct":true,"visible":false},{"text":"Insomnia","correct":false,"visible":false},{"text":"Presbycusis","correct":false,"visible":false}]},{"id":2517,"text":"The deficiency of vitamin A causes a pathological condition called xerophthalmia. Which of the following correctly describes it?","explanation":null,"reference":"1) Kumar V, Abbas AK, Aster JC, Perkins JA, eds. Robbins Basic Pathology. 10th ed. Elsevier; 2018: 328-329.\r\n\r\n2) Feroze KB, Kaufman EJ. Xerophthalmia. In: StatPearls. StatPearls Publishing; 2022. Accessed April 30, 2022. http://www.ncbi.nlm.nih.gov/books/NBK431094/","responses":[{"text":"Poor vision in dim light","correct":false,"visible":false},{"text":"Dryness of the cornea and conjuctiva","correct":true,"visible":false},{"text":"Thickening of a part of cornea","correct":false,"visible":false},{"text":"Poor vision at night","correct":false,"visible":false},{"text":"Dryness of cornea along with cloudy appearance","correct":false,"visible":false}]},{"id":2518,"text":"Which of the following nerves are not present in the posterior triangle?","explanation":null,"reference":"1) Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1016-1017, 1019.\r\n\r\n\r\n2) Chung KW, Chung HM, Halliday NL. BRS: Gross Anatomy. 8th ed. Wolters Kluwer Health; 2015: 337-338.","responses":[{"text":"Great auricular nerve","correct":false,"visible":false},{"text":"Spinal part of accessory nerve","correct":false,"visible":false},{"text":"Transverse cervical nerve","correct":false,"visible":false},{"text":"Supraclavicular nerve","correct":false,"visible":false},{"text":"Recurrent laryngeal nerve","correct":true,"visible":false}]},{"id":2521,"text":"If the anterior 2/3rd portion of the tongue is damaged then which of the following will be lost?","explanation":null,"reference":"1) Siddiqui LH. Medical Histology Text And Atlas. 6th ed. Paramount; 2019: 170-171.\r\n\r\n\r\n\r\n2) Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 676.","responses":[{"text":"Vallate papillae","correct":false,"visible":false},{"text":"Filiform papillae","correct":false,"visible":false},{"text":"Fungiform papillae","correct":true,"visible":false},{"text":"Lingual papillae","correct":false,"visible":false},{"text":"Foliate papillae","correct":false,"visible":false}]},{"id":2523,"text":"Which epithelium lines the interlobular, interlobar, and excretory duct of the lingual gland respectively?","explanation":null,"reference":"Siddiqui LH. Medical Histology Text And Atlas. 6th ed. Paramount; 2019: 193.","responses":[{"text":"Stratified columnar, simple cuboidal, pseudostratified columnar","correct":false,"visible":false},{"text":"All three are stratified columnar","correct":false,"visible":false},{"text":"Simple cuboidal, simple cuboidal, stratified columnar","correct":false,"visible":false},{"text":"Simple cuboidal, stratified columnar, stratified columnar","correct":false,"visible":false},{"text":"Simple cuboidal, pseudostratified columnar, stratified columnar","correct":true,"visible":false}]},{"id":2524,"text":"What is the hearing loss in old age termed as?","explanation":null,"reference":"Fischer N, Weber B, Riechelmann H. [presbycusis - age related hearing loss]. Laryngo- Rhino- Otologie. Published July 2016. https://pubmed.ncbi.nlm.nih.gov/27392191/","responses":[{"text":"Otitis media","correct":false,"visible":false},{"text":"Presbycusis","correct":true,"visible":false},{"text":"Vestibular neuronitis","correct":false,"visible":false},{"text":"Otitis sclerosis","correct":false,"visible":false},{"text":"Labyrinthitis","correct":false,"visible":false}]},{"id":2525,"text":"Which fibers are responsible for the retraction of the mandible?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 936.","responses":[{"text":"Middle fibers of temporalis","correct":false,"visible":false},{"text":"Masseter","correct":false,"visible":false},{"text":"Lateral pterygoid","correct":false,"visible":false},{"text":"Posterior fibers of temporalis","correct":true,"visible":false},{"text":"Medial pterygoid","correct":false,"visible":false}]},{"id":2526,"text":"Which of the following muscles causes forceful closure of the eyes?","explanation":"The muscle that causes forceful closure of the eyes is the **orbital part of the orbicularis oculi** muscle. The orbicularis oculi is a facial muscle that encircles the eye and consists of three parts: orbital, palpebral, and lacrimal.\r\n\r\nThe orbital part of the orbicularis oculi is responsible for forcefully closing the eyelids. It contracts during activities such as blinking, squinting, and forcefully closing the eyes to protect them from foreign objects or excessive light. It plays a crucial role in maintaining the health and integrity of the eyes.\r\n\r\nThe palpebral part of the orbicularis oculi is responsible for gentle closure of the eyelids, while the lacrimal part contributes to the drainage of tears from the eye.","reference":"Halliday NL, Chung HM. BRS: Gross Anatomy. 9th ed. Wolters Kluwer; 2019: 363.","responses":[{"text":"Procerus","correct":false,"visible":false},{"text":"Palpebral part of orbicularis oculi","correct":false,"visible":false},{"text":"Orbital part of orbicularis oculi","correct":true,"visible":false},{"text":"Lacrimal part of orbicularis oculi","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false}]},{"id":2527,"text":"A man is having problems maintaining balance while rotating his head. Which of the following has the defect?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 516.","responses":[{"text":"Cochlea","correct":false,"visible":false},{"text":"Semicircular canals","correct":true,"visible":false},{"text":"Cilia","correct":false,"visible":false},{"text":"Eustachian tube","correct":false,"visible":false},{"text":"Vestibule","correct":false,"visible":false}]},{"id":2529,"text":"Which of the following forms are most easily interconvertible?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 386.","responses":[{"text":"Retinoic acid and beta-carotene","correct":false,"visible":false},{"text":"Retinol and retinoic acid","correct":false,"visible":false},{"text":"Retinal and retinoic acid","correct":false,"visible":false},{"text":"Retinol and retinyl esters","correct":false,"visible":false},{"text":"Retinal and retinol","correct":true,"visible":false}]},{"id":2531,"text":"Which of the following does not drain into the middle nasal meatus?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1065.","responses":[{"text":"Frontal sinus","correct":false,"visible":false},{"text":"Middle ethmoidal air cells","correct":false,"visible":false},{"text":"Maxillay sinus","correct":false,"visible":false},{"text":"Anterior ethmoidal air cells","correct":false,"visible":false},{"text":"Sphenoidal sinus","correct":true,"visible":false}]},{"id":2533,"text":"Which structure does not pass through the superior orbital fissure?","explanation":"The **superior orbital fissure** is a bony opening located in the posterior part of the orbit, between the greater and lesser wings of the sphenoid bone. It serves as a pathway for several important structures that innervate the eye and control its movements.\r\n\r\nThe structures that pass through the superior orbital fissure include the oculomotor nerve (cranial nerve III), which supplies most of the extraocular muscles except for the superior oblique and the lateral rectus muscles. The abducens nerve (cranial nerve VI) innervates the lateral rectus muscle, while the trochlear nerve (cranial nerve IV) innervates the superior oblique muscle. The superior ophthalmic vein, which drains blood from the orbit, also passes through the superior orbital fissure.\r\n\r\nHowever, the **optic nerve**, responsible for transmitting visual information from the retina to the brain, does not pass through the superior orbital fissure. Instead, it enters the orbit through the optic canal, a separate opening in the lesser wing of the sphenoid bone.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 193.","responses":[{"text":"Superior ophthalmic vein","correct":false,"visible":false},{"text":"Oculomotor nerve","correct":false,"visible":false},{"text":"Optic nerve","correct":true,"visible":false},{"text":"Trochlear nerve","correct":false,"visible":false},{"text":"Abducens nerve","correct":false,"visible":false}]},{"id":2534,"text":"A girl is facing pre-pubertal acne. The doctor warns her about not squeezing any pimples and prescribes her some special cream for the tip of the nose and the upper lip region acne. What is the most likely reason?","explanation":"The most likely reason the doctor prescribed a special cream for the tip of the nose and the upper lip region acne is that this area has **direct dural venous drainage**. Acne in this region can be of concern due to its proximity to the facial veins, which have direct communication with the intracranial dural sinuses.\r\n\r\nThe veins in the area of the tip of the nose and upper lip region, known as the \"dangerous area of the face,\" lack the protective valve mechanism found in other facial veins. Consequently, any infection or inflammation in this region has the potential to spread directly to the intracranial venous sinuses, such as the cavernous sinus. This can lead to serious complications, including cavernous sinus thrombosis, which is a life-threatening condition.","reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 909.","responses":[{"text":"This area has direct dural venous drainage","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"This area requires more special care than the others","correct":false,"visible":false},{"text":"This area is richly vascularized","correct":false,"visible":false},{"text":"This area is more prone to acne","correct":false,"visible":false}]},{"id":2535,"text":"Which of the following structures is a content of the pterygopalatine fossa?","explanation":"One of the structures that is a content of the pterygopalatine fossa is the **3rd part of the maxillary artery**.\r\n\r\nThe pterygopalatine fossa is a small space located deep within the skull, behind the maxilla and lateral to the nasal cavity. It serves as a crossroads for several important structures. One of these structures is the maxillary artery, which is a major branch of the external carotid artery. The maxillary artery enters the pterygopalatine fossa and passes through its 3rd part before continuing on to supply various structures in the face and oral cavity.\r\n\r\nThe 3rd part of the maxillary artery gives off several branches within the pterygopalatine fossa, including the posterior superior alveolar artery, infraorbital artery, and descending palatine artery. These branches contribute to the blood supply of the teeth, gums, palate, and other structures in the region.","reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 983.","responses":[{"text":"3rd part of the maxillary artery","correct":true,"visible":false},{"text":"Infraorbital nerve","correct":false,"visible":false},{"text":"Otic ganglion","correct":false,"visible":false},{"text":"1st part of the maxillary artery","correct":false,"visible":false},{"text":"2nd part of maxillary artery","correct":false,"visible":false}]},{"id":2536,"text":"Which of the following statements regarding the tongue is incorrect?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 11th ed. Saunders/Elsevier; 2020: 172.","responses":[{"text":"Lateral swellings merge and overlap tuberculum impar to form the anterior 2/3rd of the tongue","correct":false,"visible":false},{"text":"The development of tongue begins in the fourth week of embryonic life","correct":false,"visible":false},{"text":"The tuberculum impar eventually degenerates","correct":false,"visible":false},{"text":"Hypobranchial eminemce is derived from the 3rd and 4th pharyngeal arch","correct":false,"visible":false},{"text":"Muscles of the tongue are derived from ectoderm","correct":true,"visible":false}]},{"id":2537,"text":"Which of the following is true regarding the salivary glands?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 332.","responses":[{"text":"Submandibular gland secretions are mainly mucus","correct":false,"visible":false},{"text":"The submandibular gland is the largest salivary gland","correct":false,"visible":false},{"text":"20% of salivary secretions are produced by small salivary glands","correct":false,"visible":false},{"text":"Parotid gland secretions are seromucous","correct":false,"visible":false},{"text":"Lingual gland secretions are predominantly mucus","correct":true,"visible":false}]},{"id":2538,"text":"The contrast border in the visual image is enhanced due to the lateral inhibition of which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 648.","responses":[{"text":"Bipolar cells","correct":false,"visible":false},{"text":"Amacrine cells","correct":false,"visible":false},{"text":"Photoreceptors","correct":false,"visible":false},{"text":"Horizontal cells","correct":true,"visible":false},{"text":"Ganglionic cells","correct":false,"visible":false}]},{"id":2543,"text":"Umami taste fibers are related to?","explanation":"Umami taste fibers are primarily related to **glutamate**. Glutamate is an amino acid and Umami is one of the five basic tastes, alongside sweet, sour, salty, and bitter. Umami, often described as a savory or meaty taste, is largely attributed to the presence of glutamate in food.\r\n\r\nGlutamate receptors on the taste buds detect the presence of glutamate molecules and initiate the transmission of signals to the brain, resulting in the perception of umami taste. Glutamate is naturally found in various foods such as meat, fish, mushrooms, and certain vegetables.\r\n\r\nThe recognition of umami taste is essential for the enjoyment and satisfaction of savory flavors in our diet. It adds depth and richness to food, enhancing its palatability.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 675-676.","responses":[{"text":"Alkaloids","correct":false,"visible":false},{"text":"Glutamate","correct":true,"visible":false},{"text":"Acetic acid","correct":false,"visible":false},{"text":"Organic substances containing nitrogen","correct":false,"visible":false},{"text":"Fructose","correct":false,"visible":false}]},{"id":2544,"text":"Hypermetropia is treated by which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 633.","responses":[{"text":"Concave lens","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Convex lens","correct":true,"visible":false},{"text":"Contact lens","correct":false,"visible":false},{"text":"Concavo convex lens","correct":false,"visible":false}]},{"id":2553,"text":"Myopia is corrected by what type of lens?","explanation":"Myopia, commonly known as nearsightedness, is a refractive error of the eye that causes distant objects to appear blurred, while close objects can be seen clearly. It occurs when the eyeball is longer than normal or the cornea is excessively curved, causing light to focus in front of the retina instead of directly on it.\r\n\r\nTo correct myopia, a **concave lens** is used. A concave lens is thinner at the center and thicker at the edges, causing light rays entering the eye to diverge before reaching the lens of the eye. This divergence helps to shift the focal point backward onto the retina, allowing for clear vision of distant objects.\r\n\r\nWhen a person with myopia wears concave lenses, the lenses help to properly refract light and focus it directly on the retina, resulting in clearer distance vision. The concave lens helps to correct the refractive error by diverging the incoming light and moving the focal point to the correct position on the retina.","reference":"Hall JE. Guyton and Hall Textbook of Medical Physiology. 13th ed. Elsevier; 2016: 641.","responses":[{"text":"Convex","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Concave","correct":true,"visible":false},{"text":"Imaginary","correct":false,"visible":false},{"text":"Mixed","correct":false,"visible":false}]},{"id":2554,"text":"A 25-year-old man comes into the outpatient department with the complaint of not being able to lift his shoulder. What is the most probable site of the lesion that is causing this?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 842.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Foramen ovale","correct":false,"visible":false},{"text":"Foramen magnum","correct":false,"visible":false},{"text":"Foramen rotundum","correct":false,"visible":false},{"text":"Jugular foramen","correct":true,"visible":false}]},{"id":2555,"text":"Which of the following statements about the tongue is incorrect?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 11th ed. Saunders/Elsevier; 2020: 172.","responses":[{"text":"Anterior two-thirds of the tongue is innervated differently from the posterior one-third","correct":false,"visible":false},{"text":"Foramen cecum is the site of thyroid migration","correct":false,"visible":false},{"text":"Musculature of the tongue is derived from ectoderm","correct":true,"visible":false},{"text":"Anterior two-thirds of the tongue is formed by lateral lingual swellings","correct":false,"visible":false},{"text":"Taste buds develop on the dorsal surface of tongue","correct":false,"visible":false}]},{"id":2557,"text":"Ossification and bone formation does not occur in which of the following structures?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1096.","responses":[{"text":"Hard palate","correct":false,"visible":false},{"text":"Middle ear cavity","correct":false,"visible":false},{"text":"Soft palate","correct":true,"visible":false},{"text":"Nasal septum","correct":false,"visible":false},{"text":"Lateral leg compartment","correct":false,"visible":false}]}
]

